from abc import ABC, abstractmethod

# Base class
class Animal(ABC):
    """Abstract base class for all animals"""

    def __init__(self, name, age):
        self.name = name
        self.age = age

    @abstractmethod
    def speak(self):
        """Abstract method that subclasses must implement"""
        pass

    def move(self):
        return f"{self.name} is moving"

    def info(self):
        return f"{self.name} is {self.age} years old"

# Subclass with inheritance
class Dog(Animal):
    """Dog class inheriting from Animal"""

    def __init__(self, name, age, breed):
        super().__init__(name, age)  # Call parent constructor
        self.breed = breed

    def speak(self):
        return f"{self.name} says Woof!"

    def wag_tail(self):
        return f"{self.name} is wagging tail"

    def info(self):
        # Override and extend parent method
        parent_info = super().info()
        return f"{parent_info}, Breed: {self.breed}"

class Cat(Animal):
    """Cat class inheriting from Animal"""

    def __init__(self, name, age, color):
        super().__init__(name, age)
        self.color = color

    def speak(self):
        return f"{self.name} says Meow!"

    def purr(self):
        return f"{self.name} is purring"

    def info(self):
        parent_info = super().info()
        return f"{parent_info}, Color: {self.color}"

# Polymorphism - same interface, different behavior
def animal_sound(animal):
    """Function that works with any Animal subclass"""
    return animal.speak()

def animal_details(animal):
    return animal.info()

# Creating instances
dog = Dog("Buddy", 3, "Golden Retriever")
cat = Cat("Whiskers", 2, "Orange")

# Using polymorphism
print(animal_sound(dog))  # Buddy says Woof!
print(animal_sound(cat))  # Whiskers says Meow!
print(animal_details(dog))  # Buddy is 3 years old, Breed: Golden Retriever
print(animal_details(cat))  # Whiskers is 2 years old, Color: Orange

# Multiple inheritance
class FlyingMixin:
    """Mixin class providing flying capability"""

    def fly(self):
        return f"{self.name} is flying"

    def land(self):
        return f"{self.name} is landing"

class Bird(Animal, FlyingMixin):
    """Bird inherits from Animal and FlyingMixin"""

    def __init__(self, name, age, species):
        super().__init__(name, age)
        self.species = species

    def speak(self):
        return f"{self.name} says Chirp!"

    def info(self):
        return f"{super().info()}, Species: {self.species}"

bird = Bird("Tweety", 1, "Canary")
print(bird.fly())      # Tweety is flying
print(bird.speak())    # Tweety says Chirp!
print(bird.info())     # Tweety is 1 years old, Species: Canary

# Method Resolution Order (MRO)
print(Bird.__mro__)  # Shows method resolution order

class Employee:
    """Employee class with encapsulated attributes and property access"""

    def __init__(self, name, salary, employee_id):
        self.name = name  # Public attribute
        self._department = "Engineering"  # Protected (convention)
        self.__employee_id = employee_id  # Private (name mangling)
        self._salary = salary  # Protected attribute for property
        self._performance_rating = 3  # Default rating

    # Property for salary with validation
    @property
    def salary(self):
        """Getter for salary"""
        return self._salary

    @salary.setter
    def salary(self, value):
        """Setter with validation"""
        if value < 0:
            raise ValueError("Salary cannot be negative")
        if value < 30000:
            print("Warning: Low salary")
        self._salary = value
        # Automatically update performance rating based on salary
        self._update_performance_rating()

    @salary.deleter
    def salary(self):
        """Deleter for salary"""
        print("Cannot delete salary!")

    # Read-only property for employee ID
    @property
    def employee_id(self):
        """Read-only property - no setter"""
        return self.__employee_id

    # Property with computed value
    @property
    def annual_salary(self):
        """Compute annual salary from monthly salary"""
        return self._salary * 12

    # Property with getter and setter
    @property
    def performance_rating(self):
        return self._performance_rating

    @performance_rating.setter
    def performance_rating(self, rating):
        if 1 <= rating <= 5:
            self._performance_rating = rating
            self._update_salary_based_on_rating()
        else:
            raise ValueError("Rating must be between 1 and 5")

    # Private helper methods
    def _update_performance_rating(self):
        """Update performance rating based on salary"""
        if self._salary > 100000:
            self._performance_rating = 5
        elif self._salary > 75000:
            self._performance_rating = 4
        elif self._salary > 50000:
            self._performance_rating = 3

    def _update_salary_based_on_rating(self):
        """Update salary based on performance rating"""
        if self._performance_rating >= 4:
            self._salary *= 1.10  # 10% raise

    def __str__(self):
        return f"Employee: {self.name}, Salary: ${self._salary:,.2f}, ID: {self.__employee_id}"

    def get_department(self):
        """Getter for protected attribute"""
        return self._department

    def set_department(self, department):
        """Setter with validation for protected attribute"""
        valid_departments = ["Engineering", "Sales", "Marketing", "HR"]
        if department in valid_departments:
            self._department = department
        else:
            raise ValueError(f"Invalid department. Choose from {valid_departments}")

# Using encapsulation and properties
emp = Employee("Alice", 60000, "EMP001")

# Using property getter
print(emp.salary)  # 60000 (calls getter)
print(emp.annual_salary)  # 720000 (computed property)

# Using property setter with validation
emp.salary = 80000
print(emp.salary)  # 80000
print(emp.performance_rating)  # 4 (auto-updated)

# Using read-only property
print(emp.employee_id)  # EMP001
# emp.employee_id = "NEW_ID"  # AttributeError: can't set attribute

# Using property with validation
try:
    emp.performance_rating = 6  # Raises ValueError
except ValueError as e:
    print(f"Error: {e}")

emp.performance_rating = 5
print(emp.salary)  # 88000 (auto-updated due to rating)

# Accessing protected attributes (convention, not enforced)
print(emp._department)  # Engineering (works but discouraged)

# Name mangling for private attributes
print(emp._Employee__employee_id)  # EMP001 (still accessible but name-mangled)
# print(emp.__employee_id)  # AttributeError: 'Employee' object has no attribute '__employee_id'

# Using getter/setter methods for protected attribute
print(emp.get_department())  # Engineering
emp.set_department("Sales")
print(emp.get_department())  # Sales

print(emp)  # Employee: Alice, Salary: $88,000.00, ID: EMP001

class Vector:
    """Vector class demonstrating magic methods"""

    def __init__(self, x, y):
        """Constructor"""
        self.x = x
        self.y = y

    # String representation methods
    def __str__(self):
        """User-friendly string representation"""
        return f"Vector({self.x}, {self.y})"

    def __repr__(self):
        """Developer-friendly representation"""
        return f"Vector({self.x}, {self.y})"

    # Arithmetic operators
    def __add__(self, other):
        """Overload + operator"""
        if isinstance(other, Vector):
            return Vector(self.x + other.x, self.y + other.y)
        return NotImplemented

    def __sub__(self, other):
        """Overload - operator"""
        if isinstance(other, Vector):
            return Vector(self.x - other.x, self.y - other.y)
        return NotImplemented

    def __mul__(self, scalar):
        """Overload * operator (scalar multiplication)"""
        if isinstance(scalar, (int, float)):
            return Vector(self.x * scalar, self.y * scalar)
        return NotImplemented

    def __rmul__(self, scalar):
        """Reverse multiplication for scalar * vector"""
        return self.__mul__(scalar)

    # Comparison operators
    def __eq__(self, other):
        """Overload == operator"""
        if isinstance(other, Vector):
            return self.x == other.x and self.y == other.y
        return False

    def __lt__(self, other):
        """Overload < operator (compare magnitude)"""
        if isinstance(other, Vector):
            return (self.x**2 + self.y**2) < (other.x**2 + other.y**2)
        return NotImplemented

    # Container methods (make vector behave like sequence)
    def __len__(self):
        """Return length (magnitude)"""
        return int((self.x ** 2 + self.y ** 2) ** 0.5)

    def __getitem__(self, index):
        """Enable indexing: v[0], v[1]"""
        if index == 0:
            return self.x
        elif index == 1:
            return self.y
        else:
            raise IndexError("Vector index out of range")

    def __setitem__(self, index, value):
        """Enable item assignment: v[0] = 5"""
        if index == 0:
            self.x = value
        elif index == 1:
            self.y = value
        else:
            raise IndexError("Vector index out of range")

    def __iter__(self):
        """Make vector iterable"""
        yield self.x
        yield self.y

    # Callable object
    def __call__(self, factor):
        """Make instance callable: v(2) scales the vector"""
        return Vector(self.x * factor, self.y * factor)

    # Context manager support
    def __enter__(self):
        """Enter context manager"""
        print(f"Entering context with vector {self}")
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        """Exit context manager"""
        print(f"Exiting context with vector {self}")
        return False  # Don't suppress exceptions

# Using magic methods
v1 = Vector(2, 3)
v2 = Vector(4, 5)

# String representation
print(str(v1))  # Vector(2, 3)
print(repr(v1))  # Vector(2, 3)

# Arithmetic operators
v3 = v1 + v2
print(v3)  # Vector(6, 8)
v4 = v2 - v1
print(v4)  # Vector(2, 2)
v5 = v1 * 3
print(v5)  # Vector(6, 9)
v6 = 4 * v1  # Uses __rmul__
print(v6)  # Vector(8, 12)

# Comparison operators
print(v1 == Vector(2, 3))  # True
print(v1 < v2)  # True (magnitude of v1 < v2)

# Container behavior
print(len(v1))  # 3 (magnitude rounded down)
print(v1[0])  # 2
print(v1[1])  # 3
v1[0] = 10
print(v1)  # Vector(10, 3)

# Iteration
for component in v1:
    print(component)  # 10, 3

# Callable object
v7 = v1(2)  # Scale vector by 2
print(v7)  # Vector(20, 6)

# Context manager
with Vector(1, 2) as v:
    print(f"Working with {v}")
# Output: Entering context with Vector(1, 2)
#         Working with Vector(1, 2)
#         Exiting context with Vector(1, 2)

# More magic methods
class CustomList:
    """Demonstrating more magic methods"""

    def __init__(self, items):
        self.items = list(items)

    def __contains__(self, item):
        """Support 'in' operator"""
        return item in self.items

    def __bool__(self):
        """Support boolean conversion"""
        return len(self.items) > 0

    def __hash__(self):
        """Support hashing (if immutable)"""
        return hash(tuple(self.items))

    def __reversed__(self):
        """Support reversed()"""
        return reversed(self.items)

cl = CustomList([1, 2, 3])
print(2 in cl)  # True
print(bool(cl))  # True
print(list(reversed(cl)))  # [3, 2, 1]
